+fn matrix_rank_default_rcond(dtype: DType, max_dim: usize) -> Option<f64> {
+    let epsilon = match dtype {
+        DType::Bool
+        | DType::I8
+        | DType::I16
+        | DType::I32
+        | DType::I64
+        | DType::U8
+        | DType::U16
+        | DType::U32
+        | DType::U64
+        | DType::F64 => f64::EPSILON,
+        DType::F32 => f32::EPSILON as f64,
+        _ => return None,
+    };
+    Some((max_dim as f64) * epsilon)
+}
